// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PresaleMint {
    enum State { PresaleLive, SaleLive, SaleClosed }
    State public currentState = State.PresaleLive;

    address private owner;
    mapping(address => bool) public presalerList;
    uint256 public presaleAmountMinted;
    uint256 public publicAmountMinted;

    event WhitelistUpdated(address indexed user, bool status);
    event SaleToggled(State newState);
    event PresaleMinted(address indexed user, uint256 amount);
    event PublicMinted(address indexed user, uint256 amount);
    event EtherWithdrawn(address indexed to, uint256 amount);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    function whitelist(address user, bool status) public onlyOwner {
        presalerList[user] = status;
        emit WhitelistUpdated(user, status);
    }

    function toggleSale() public onlyOwner {
        if (currentState == State.PresaleLive) {
            currentState = State.SaleLive;
            emit SaleToggled(State.SaleLive);
        } else if (currentState == State.SaleLive) {
            currentState = State.SaleClosed;
            emit SaleToggled(State.SaleClosed);
        }
    }

    function presaleBuy() external payable {
        require(currentState == State.PresaleLive, "Presale not live");
        require(presalerList[msg.sender], "Not whitelisted");
        presaleAmountMinted++;
        emit PresaleMinted(msg.sender, 1);
    }

    function buy() external payable {
        require(currentState == State.SaleLive, "Sale not live");
        publicAmountMinted++;
        emit PublicMinted(msg.sender, 1);
    }

    function withdraw() external onlyOwner {
        emit EtherWithdrawn(owner, address(this).balance);
        payable(owner).transfer(address(this).balance);
    }
}
